mapper.update:
UPDATE TB_CONTRACT SET
	CONTRACT_NAME = #{CONTRACT_NAME}
	, CONTRACT_DATE = REPLACE(#{CONTRACT_DATE}, '/', '')
	, AMOUNT = REPLACE(#{AMOUNT}, ',', '')
	, START_DATE = REPLACE(#{START_DATE}, '/', '')
	, END_DATE = REPLACE(#{END_DATE}, '/', '')
	, DEL_YN = COALESCE(#{DEL_YN}, 'N')
	, UPD_USER_ID = #{UPD_USER_ID}
	, UPD_DT = CURRENT TIMESTAMP
WHERE CONTRACT_TYPE_CD = #{CONTRACT_TYPE_CD}
AND CONTRACT_NO = #{CONTRACT_NO}
AND COALESCE(DEL_YN, 'N') = 'N'
